INSERT INTO dbai_knowledge.system_memory (category, title, content, structured_data, tags, author) VALUES ('architecture', 'Ghost Browser Architecture', 'Ghost Browser nutzt Playwright (headless Chromium) im Backend. Der User gibt einen Auftrag per Prompt, Ghost navigiert automatisch, extrahiert Daten und erstellt Ergebnis-Dateien (MD/JSON/CSV). Sicherheit: Sandbox-Modus (kein Login), max_pages, max_duration. Screenshots werden bei jedem Schritt gespeichert.', $json${"components": {"backend": "bridge/browser_agent.py", "api": "web/server.py /api/ghost-browser/*", "frontend": "GhostBrowser.jsx", "schema": "schema/56-ghost-browser.sql"}, "tables": ["dbai_system.ghost_browser_tasks", "dbai_system.ghost_browser_steps", "dbai_system.ghost_browser_presets"]}$json$::jsonb, ARRAY['ghost-browser','playwright','chromium','ai-agent','v0.11.0'], 'ghost-agent') ON CONFLICT DO NOTHING;
